const __pageData = JSON.parse('{"title":"单元测试深度：隔离与确定性","description":"系统阐述单元测试的FIRST原则与测试替身理论，深入剖析Jest与Vitest的配置策略、Mock机制、异步测试与覆盖率阈值，并提供JS/TS生态的最佳实践指南。","frontmatter":{"title":"单元测试深度：隔离与确定性","description":"系统阐述单元测试的FIRST原则与测试替身理论，深入剖析Jest与Vitest的配置策略、Mock机制、异步测试与覆盖率阈值，并提供JS/TS生态的最佳实践指南。","date":"2026-05-01T00:00:00.000Z","tags":["测试工程","单元测试","Jest","Vitest","Mock","测试覆盖率"],"category":"engineering"},"headers":[],"relativePath":"testing-engineering/02-unit-testing-deep-dive.md","filePath":"testing-engineering/02-unit-testing-deep-dive.md","lastUpdated":1777741461000}');
